import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.owasp.esapi.ESAPI;

public class XSSSecureCode {

    public void handleUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Properly handle user input by encoding it to prevent XSS
        String encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);

        response.getWriter().println("<h1>User Input: " + encodedUserInput + "</h1>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
